import{_ as e,o as s,c as t,a2 as i}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"SIP Capture","description":"","frontmatter":{},"headers":[],"relativePath":"features/sip-capture.md","filePath":"features/sip-capture.md"}'),l={name:"features/sip-capture.md"};function n(r,a,p,o,c,d){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="sip-capture" tabindex="-1">SIP Capture <a class="header-anchor" href="#sip-capture" aria-label="Permalink to &quot;SIP Capture&quot;">​</a></h1><p>SIP Capture gives you a live view of SIP signaling as it moves through the system. It helps troubleshoot registration problems, trunk issues, call setup failures, and provider-side disputes without leaving the Callytics UI.</p><p>The capture view can be filtered by method, Call-ID, trunk, and time range so you can narrow the stream to the traffic that matters. For a completed call, the per-call ladder diagram shows the SIP conversation in sequence, making it easier to understand where a call succeeded or failed.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>SIP Capture has two parallel data paths: an AMI-based path that is always active, and an optional tshark path for raw packet capture.</p><h3 id="ami-pjsip-logger-path" tabindex="-1">AMI PJSIP logger path <a class="header-anchor" href="#ami-pjsip-logger-path" aria-label="Permalink to &quot;AMI PJSIP logger path&quot;">​</a></h3><p>This path is always active when the system is running.</p><ol><li>Stasis enables <code>pjsip set logger on</code> via AMI on startup</li><li>Asterisk emits parsed SIP messages as AMI events</li><li>Stasis receives these AMI events and publishes them to the Redis pub/sub channel <code>callytics:sip-traffic</code></li><li>The NestJS backend subscribes to <code>callytics:sip-traffic</code> and relays each message to the browser via Socket.IO (<code>sip:traffic</code> event)</li><li>The SIP Capture page in the browser receives the stream and displays messages in real time</li></ol><h3 id="tshark-path" tabindex="-1">tshark path <a class="header-anchor" href="#tshark-path" aria-label="Permalink to &quot;tshark path&quot;">​</a></h3><p>This path requires <code>TSHARK_ENABLED=true</code> in the Asterisk container environment.</p><ol><li>A capture sidecar process starts inside the Asterisk container and runs <code>tshark -i any -f &quot;udp port 5080&quot;</code> continuously</li><li>The sidecar restarts automatically if tshark exits</li><li>Raw captured packets are published to the Redis stream <code>callytics:sip-capture</code></li><li>The backend consumes the stream and relays packets to the browser via Socket.IO (<code>sip:capture-packet</code> event)</li></ol><h3 id="per-call-filtering" tabindex="-1">Per-call filtering <a class="header-anchor" href="#per-call-filtering" aria-label="Permalink to &quot;Per-call filtering&quot;">​</a></h3><p>Each SIP message is stored with the value of its <code>Call-ID</code> header. The UI uses this to filter the capture stream to a single SIP dialog.</p><p>When you open a specific call in Call Logs and click the SIP Capture link, the view is pre-filtered by that call&#39;s Call-ID. If the Callytics internal call ID does not map directly to a SIP Call-ID, the UI falls back to matching by timestamp proximity — finding SIP messages within a small time window around the call.</p><h3 id="sip-ladder-diagram" tabindex="-1">SIP ladder diagram <a class="header-anchor" href="#sip-ladder-diagram" aria-label="Permalink to &quot;SIP ladder diagram&quot;">​</a></h3><p>The per-call SIP ladder diagram is built entirely in the browser in <code>SipLadderPanel.tsx</code>. The backend returns the SIP messages for a call as structured data. The frontend renders the SVG ladder diagram client-side from that data — no server-side rendering is involved.</p><h3 id="capture-path-overview" tabindex="-1">Capture path overview <a class="header-anchor" href="#capture-path-overview" aria-label="Permalink to &quot;Capture path overview&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Asterisk PJSIP logger          tshark sidecar</span></span>
<span class="line"><span>        │                            │</span></span>
<span class="line"><span>        │ AMI events                 │ udp port 5080</span></span>
<span class="line"><span>        ▼                            ▼</span></span>
<span class="line"><span>   callytics:sip-traffic      callytics:sip-capture</span></span>
<span class="line"><span>   (Redis pub/sub)             (Redis stream)</span></span>
<span class="line"><span>        │                            │</span></span>
<span class="line"><span>        └────────────┬───────────────┘</span></span>
<span class="line"><span>                     ▼</span></span>
<span class="line"><span>               NestJS backend</span></span>
<span class="line"><span>               Socket.IO</span></span>
<span class="line"><span>                     │</span></span>
<span class="line"><span>                     ▼</span></span>
<span class="line"><span>                  Browser</span></span>
<span class="line"><span>            ┌─────────────────┐</span></span>
<span class="line"><span>            │  packet table   │</span></span>
<span class="line"><span>            │  SIP ladder SVG │</span></span>
<span class="line"><span>            │  .pcap export   │</span></span>
<span class="line"><span>            └─────────────────┘</span></span></code></pre></div><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Live SIP packet stream</li><li>Method, Call-ID, trunk, and time filters</li><li>Per-call SIP ladder diagram</li><li>Historical packet retrieval for completed calls</li><li>Rule-based verdict banner for quick interpretation</li><li>Packet header inspection</li><li>PCAP export for a selected dialog</li><li>Bulk PCAP export from the capture view</li><li>Deep link from call logs to capture filtered by Call-ID</li></ul>`,20)])])}const m=e(l,[["render",n]]);export{u as __pageData,m as default};
